   170	void dlsch_scheduler_pre_ue_select_fairRR(
   171	  module_id_t     module_idP,
   172	  frame_t         frameP,
   173	  sub_frame_t     subframeP,
   174	  int            *mbsfn_flag,
   175	  uint16_t        nb_rbs_required[MAX_NUM_CCs][MAX_MOBILES_PER_ENB],
   176	  DLSCH_UE_SELECT dlsch_ue_select[MAX_NUM_CCs]) {
   177	  eNB_MAC_INST                   *eNB      = RC.mac[module_idP];
   178	  COMMON_channels_t              *cc       = eNB->common_channels;
   179	  UE_info_t                      *UE_info  = &eNB->UE_info;
   180	  UE_sched_ctrl_t                  *ue_sched_ctl;
   181	  uint8_t                        CC_id;
   182	  int                            UE_id;
   183	  unsigned char                  round             = 0;
   184	  unsigned char                  harq_pid          = 0;
   185	  rnti_t                         rnti;
   186	  uint16_t                       i;
   187	  unsigned char                  aggregation;
   188	  int                            format_flag;
   189	  nfapi_dl_config_request_body_t *DL_req;
   190	  nfapi_dl_config_request_pdu_t  *dl_config_pdu;
   191	  uint16_t                       dlsch_ue_max_num[MAX_NUM_CCs] = {0};
   192	  uint16_t                       saved_dlsch_dci[MAX_NUM_CCs] = {0};
   193	  uint8_t                        end_flag[MAX_NUM_CCs] = {0};
   194	
   195	  // Initialization
   196	  for (CC_id = 0; CC_id < MAX_NUM_CCs; CC_id++) {
   197	    dlsch_ue_max_num[CC_id] = eNB->ue_multiple_max;
   198	    // save origin DL PDU number
   199	    DL_req          = &eNB->DL_req[CC_id].dl_config_request_body;
   200	    saved_dlsch_dci[CC_id] = DL_req->number_pdu;

  saved_dlsch_dci[CC_id] = DL_req->number_pdu;
}

// Insert DLSCH(retransmission) UE into selected UE list
for (CC_id = 0; CC_id < MAX_NUM_CCs; CC_id++) {
  if (mbsfn_flag[CC_id]>0) {
    continue;
  }

  DL_req          = &eNB->DL_req[CC_id].dl_config_request_body;

  for (UE_id = 0; UE_id < NUMBER_OF_UE_MAX; UE_id++) {
    if (UE_info->active[UE_id] == false) {
      continue;
    }

    rnti = UE_RNTI(module_idP, UE_id);

    if (rnti == NOT_A_RNTI) {
      continue;
    }


    if (UE_info->UE_sched_ctrl[UE_id].ul_failure_timer > 0
        || UE_info->UE_sched_ctrl[UE_id].ul_out_of_sync == 1)
      continue;

    if(mac_eNB_get_rrc_status(module_idP,rnti) < RRC_CONNECTED) {
      continue;
    }

    ue_sched_ctl = &UE_info->UE_sched_ctrl[UE_id];
    harq_pid = frame_subframe2_dl_harq_pid(cc[CC_id].tdd_Config,frameP,subframeP);
    round = ue_sched_ctl->round[CC_id][harq_pid];

    if (round != 8) {  // retransmission
      if(UE_info->UE_template[CC_id][UE_id].nb_rb[harq_pid] == 0) {
        continue;
      }

      switch (get_tmode(module_idP, CC_id, UE_id)) {
        case 1:
        case 2:
        case 7:
          aggregation = get_aggregation(get_bw_index(module_idP, CC_id),
                                        ue_sched_ctl->dl_cqi[CC_id],
                                        format1);
          break;

        case 3:
          aggregation = get_aggregation(get_bw_index(module_idP,CC_id),
                                        ue_sched_ctl->dl_cqi[CC_id],
                                        format2A);
          break;

        default:
          LOG_W(MAC,"Unsupported transmission mode %d\n", get_tmode(module_idP,CC_id,UE_id));
          aggregation = 2;
          break;
      }

      format_flag = 1;

      if (!CCE_allocation_infeasible(module_idP,
                                     CC_id,
                                     format_flag,
                                     subframeP,
                                     aggregation,
                                     rnti)) {
        dl_config_pdu = &DL_req->dl_config_pdu_list[DL_req->number_pdu];
        dl_config_pdu->pdu_type                                     = NFAPI_DL_CONFIG_DCI_DL_PDU_TYPE;
        dl_config_pdu->dci_dl_pdu.dci_dl_pdu_rel8.rnti              = rnti;
        dl_config_pdu->dci_dl_pdu.dci_dl_pdu_rel8.rnti_type         = (format_flag == 0)?2:1;
        dl_config_pdu->dci_dl_pdu.dci_dl_pdu_rel8.aggregation_level = aggregation;
        DL_req->number_pdu++;
        nb_rbs_required[CC_id][UE_id] = UE_info->UE_template[CC_id][UE_id].nb_rb[harq_pid];
        // Insert DLSCH(retransmission) UE into selected UE list
        dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].UE_id = UE_id;
        dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].ue_priority = SCH_DL_RETRANS;
        dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].rnti = rnti;
        dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].nb_rb = nb_rbs_required[CC_id][UE_id];
        dlsch_ue_select[CC_id].ue_num++;

        if (dlsch_ue_select[CC_id].ue_num == dlsch_ue_max_num[CC_id]) {
          end_flag[CC_id] = 1;
          break;
        }
      } else {
        if (cc[CC_id].tdd_Config != NULL) { //TDD
          set_ue_dai (subframeP,
                      UE_id,
                      CC_id,
                      cc[CC_id].tdd_Config->subframeAssignment,
                      UE_info);
          // update UL DAI after DLSCH scheduling
          set_ul_DAI(module_idP,UE_id,CC_id,frameP,subframeP);
        }
        eNB_dlsch_info[module_idP][CC_id][UE_id].status = S_DL_NONE;
        end_flag[CC_id] = 1;
        break;
      }
    }
  }
}

if(cc_id_end(end_flag) == 1) {
  for (CC_id = 0; CC_id < MAX_NUM_CCs; CC_id++) {
    DL_req          = &eNB->DL_req[CC_id].dl_config_request_body;
    DL_req->number_pdu = saved_dlsch_dci[CC_id];
  }

  return;
}

// Insert DLSCH(first transmission) UE into selected UE list (UE_id > last_dlsch_ue_id[CC_id])
for (CC_id = 0; CC_id < MAX_NUM_CCs; CC_id++) {
  if (mbsfn_flag[CC_id]>0) {
    continue;
  }

  DL_req          = &eNB->DL_req[CC_id].dl_config_request_body;

  for (UE_id = (last_dlsch_ue_id[CC_id]+1); UE_id <NUMBER_OF_UE_MAX; UE_id++) {
    if(end_flag[CC_id] == 1) {
      break;
    }

    if (UE_info->active[UE_id] == false) {
      continue;
    }

    rnti = UE_RNTI(module_idP,UE_id);

    if (rnti == NOT_A_RNTI)
      continue;

    if (UE_info->UE_sched_ctrl[UE_id].ul_failure_timer > 0
        || UE_info->UE_sched_ctrl[UE_id].ul_out_of_sync == 1)
      continue;

    if(mac_eNB_get_rrc_status(module_idP,rnti) < RRC_CONNECTED) {
      continue;
    }

    ue_sched_ctl = &UE_info->UE_sched_ctrl[UE_id];

    for(i = 0; i<dlsch_ue_select[CC_id].ue_num; i++) {
      if(dlsch_ue_select[CC_id].list[i].UE_id == UE_id) {
        break;
      }
    }

        dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].nb_rb = nb_rbs_required[CC_id][UE_id];
        dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].UE_id = UE_id;
        dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].rnti = rnti;
        dlsch_ue_select[CC_id].ue_num++;

        if (dlsch_ue_select[CC_id].ue_num == dlsch_ue_max_num[CC_id]) {
          end_flag[CC_id] = 1;
          break;
        }
      } else {
        if (cc[CC_id].tdd_Config != NULL) { //TDD
          set_ue_dai (subframeP,
                      UE_id,
                      CC_id,
                      cc[CC_id].tdd_Config->subframeAssignment,
                      UE_info);
          // update UL DAI after DLSCH scheduling
          set_ul_DAI(module_idP,UE_id,CC_id,frameP,subframeP);
        }
        eNB_dlsch_info[module_idP][CC_id][UE_id].status = S_DL_NONE;
        end_flag[CC_id] = 1;
        break;
      }
    }
  }
}

if(cc_id_end(end_flag) == 1) {
  for (CC_id = 0; CC_id < MAX_NUM_CCs; CC_id++) {
    DL_req          = &eNB->DL_req[CC_id].dl_config_request_body;
    DL_req->number_pdu = saved_dlsch_dci[CC_id];
  }

  return;
}

// Insert DLSCH(first transmission) UE into selected UE list (UE_id <= last_dlsch_ue_id[CC_id])
for (CC_id = 0; CC_id < MAX_NUM_CCs; CC_id++) {
  if (mbsfn_flag[CC_id]>0) {
    continue;
  }

  DL_req          = &eNB->DL_req[CC_id].dl_config_request_body;

  for (UE_id = 0; UE_id <= last_dlsch_ue_id[CC_id]; UE_id++) {
    if(end_flag[CC_id] == 1) {
      break;
    }

    if (UE_info->active[UE_id] == false) {
      continue;
    }

    rnti = UE_RNTI(module_idP,UE_id);

    if (rnti == NOT_A_RNTI)
      continue;

    if (UE_info->UE_sched_ctrl[UE_id].ul_failure_timer > 0
        || UE_info->UE_sched_ctrl[UE_id].ul_out_of_sync == 1)
      continue;

    if(mac_eNB_get_rrc_status(module_idP,rnti) < RRC_CONNECTED) {
      continue;
    }

    ue_sched_ctl = &UE_info->UE_sched_ctrl[UE_id];

    for(i = 0; i<dlsch_ue_select[CC_id].ue_num; i++) {
      if(dlsch_ue_select[CC_id].list[i].UE_id == UE_id) {
        break;
      }
    }

    if(i < dlsch_ue_select[CC_id].ue_num)
      continue;

    harq_pid = frame_subframe2_dl_harq_pid(cc[CC_id].tdd_Config,frameP,subframeP);
    round = ue_sched_ctl->round[CC_id][harq_pid];

    if (round == 8) {
      if (nb_rbs_required[CC_id][UE_id] == 0) {
        continue;
      }

      switch (get_tmode(module_idP, CC_id, UE_id)) {
        case 1:
        case 2:
        case 7:
          aggregation = get_aggregation(get_bw_index(module_idP, CC_id),
                                        ue_sched_ctl->dl_cqi[CC_id],
                                        format1);
          break;

        case 3:
          aggregation = get_aggregation(get_bw_index(module_idP,CC_id),
                                        ue_sched_ctl->dl_cqi[CC_id],
                                        format2A);
          break;

        default:

        dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].nb_rb = nb_rbs_required[CC_id][UE_id];
        dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].UE_id = UE_id;
        dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].rnti = rnti;
        dlsch_ue_select[CC_id].ue_num++;

        if (dlsch_ue_select[CC_id].ue_num == dlsch_ue_max_num[CC_id]) {
          end_flag[CC_id] = 1;
          break;
        }
      } else {
        if (cc[CC_id].tdd_Config != NULL) { //TDD
          set_ue_dai (subframeP,
                      UE_id,
                      CC_id,
                      cc[CC_id].tdd_Config->subframeAssignment,
                      UE_info);
          // update UL DAI after DLSCH scheduling
          set_ul_DAI(module_idP,UE_id,CC_id,frameP,subframeP);
        }
        eNB_dlsch_info[module_idP][CC_id][UE_id].status = S_DL_NONE;
        end_flag[CC_id] = 1;
        break;
      }
    }
  }
}

if(cc_id_end(end_flag) == 1) {
  for (CC_id = 0; CC_id < MAX_NUM_CCs; CC_id++) {
    DL_req          = &eNB->DL_req[CC_id].dl_config_request_body;
    DL_req->number_pdu = saved_dlsch_dci[CC_id];
  }

  return;
}

// Insert DLSCH(first transmission) UE into selected UE list (UE_id <= last_dlsch_ue_id[CC_id])
for (CC_id = 0; CC_id < MAX_NUM_CCs; CC_id++) {
  if (mbsfn_flag[CC_id]>0) {
    continue;
  }

  DL_req          = &eNB->DL_req[CC_id].dl_config_request_body;

  for (UE_id = 0; UE_id <= last_dlsch_ue_id[CC_id]; UE_id++) {
    if(end_flag[CC_id] == 1) {
      break;
    }

    if (UE_info->active[UE_id] == false) {
      continue;
    }

    rnti = UE_RNTI(module_idP,UE_id);

    if (rnti == NOT_A_RNTI)
      continue;

    if (UE_info->UE_sched_ctrl[UE_id].ul_failure_timer > 0
        || UE_info->UE_sched_ctrl[UE_id].ul_out_of_sync == 1)
      continue;

    if(mac_eNB_get_rrc_status(module_idP,rnti) < RRC_CONNECTED) {
      continue;
    }

    ue_sched_ctl = &UE_info->UE_sched_ctrl[UE_id];

    for(i = 0; i<dlsch_ue_select[CC_id].ue_num; i++) {
      if(dlsch_ue_select[CC_id].list[i].UE_id == UE_id) {
        break;
      }
    }

    if(i < dlsch_ue_select[CC_id].ue_num)
      continue;

    harq_pid = frame_subframe2_dl_harq_pid(cc[CC_id].tdd_Config,frameP,subframeP);
    round = ue_sched_ctl->round[CC_id][harq_pid];

    if (round == 8) {
      if (nb_rbs_required[CC_id][UE_id] == 0) {
        continue;
      }

      switch (get_tmode(module_idP, CC_id, UE_id)) {
        case 1:
        case 2:
        case 7:
          aggregation = get_aggregation(get_bw_index(module_idP, CC_id),
                                        ue_sched_ctl->dl_cqi[CC_id],
                                        format1);
          break;

        case 3:
          aggregation = get_aggregation(get_bw_index(module_idP,CC_id),
                                        ue_sched_ctl->dl_cqi[CC_id],
                                        format2A);
          break;

        default:

          default:
            LOG_W(MAC,"Unsupported transmission mode %d\n", get_tmode(module_idP,CC_id,UE_id));
            aggregation = 2;
            break;
        }

        format_flag = 1;

        if (!CCE_allocation_infeasible(module_idP,
                                       CC_id,
                                       format_flag,
                                       subframeP,
                                       aggregation,
                                       rnti)) {
          dl_config_pdu = &DL_req->dl_config_pdu_list[DL_req->number_pdu];
          dl_config_pdu->pdu_type                                     = NFAPI_DL_CONFIG_DCI_DL_PDU_TYPE;
          dl_config_pdu->dci_dl_pdu.dci_dl_pdu_rel8.rnti              = rnti;
          dl_config_pdu->dci_dl_pdu.dci_dl_pdu_rel8.rnti_type         = (format_flag == 0)?2:1;
          dl_config_pdu->dci_dl_pdu.dci_dl_pdu_rel8.aggregation_level = aggregation;
          DL_req->number_pdu++;
          // Insert DLSCH(first transmission) UE into selected selected UE list
          dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].ue_priority = SCH_DL_FIRST;
          dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].nb_rb = nb_rbs_required[CC_id][UE_id];
