// Initialization
for (CC_id = 0; CC_id < MAX_NUM_CCs; CC_id++) {
  dlsch_ue_max_num[CC_id] = eNB->ue_multiple_max;
  // save origin DL PDU number
  DL_req          = &eNB->DL_req[CC_id].dl_config_request_body;
  saved_dlsch_dci[CC_id] = DL_req->number_pdu;
}

// Check for active SI and PAGING traffic and insert with highest priority
for (CC_id = 0; CC_id < MAX_NUM_CCs; CC_id++) {
  if (mbsfn_flag[CC_id]>0) {
    continue;
  }

  DL_req = &eNB->DL_req[CC_id].dl_config_request_body;

  // Schedule SI traffic first when SI_active == 1
  if (cc[CC_id].msi_active == 1) {
    aggregation = 4; // Use aggregation level 4 for reliability
    format_flag = 1;

    if (!CCE_allocation_infeasible(module_idP,
                                   CC_id,
                                   format_flag,
                                   subframeP,
                                   aggregation,
                                   SI_RNTI)) {
      dl_config_pdu = &DL_req->dl_config_pdu_list[DL_req->number_pdu];
      dl_config_pdu->pdu_type                                     = NFAPI_DL_CONFIG_DCI_DL_PDU_TYPE;
      dl_config_pdu->dci_dl_pdu.dci_dl_pdu_rel8.rnti              = SI_RNTI;
      dl_config_pdu->dci_dl_pdu.dci_dl_pdu_rel8.rnti_type         = 1;
      dl_config_pdu->dci_dl_pdu.dci_dl_pdu_rel8.aggregation_level = aggregation;
      DL_req->number_pdu++;

      // Insert SI into selected UE list with highest priority
      dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].UE_id = -1; // Special UE ID for SI
      dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].ue_priority = SCH_DL_SI;
      dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].rnti = SI_RNTI;
      dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].nb_rb = 0; // SI uses fixed resources
      dlsch_ue_select[CC_id].ue_num++;

      if (dlsch_ue_select[CC_id].ue_num == dlsch_ue_max_num[CC_id]) {
        end_flag[CC_id] = 1;
        continue;
      }
    }
  }

  // Schedule PAGING traffic next when PAGING_active == 1  
  if (cc[CC_id].num_pcch_active > 0) {
    aggregation = 4; // Use aggregation level 4 for reliability
    format_flag = 1;

    if (!CCE_allocation_infeasible(module_idP,
                                   CC_id,
                                   format_flag,
                                   subframeP,
                                   aggregation,
                                   P_RNTI)) {
      dl_config_pdu = &DL_req->dl_config_pdu_list[DL_req->number_pdu];
      dl_config_pdu->pdu_type                                     = NFAPI_DL_CONFIG_DCI_DL_PDU_TYPE;
      dl_config_pdu->dci_dl_pdu.dci_dl_pdu_rel8.rnti              = P_RNTI;
      dl_config_pdu->dci_dl_pdu.dci_dl_pdu_rel8.rnti_type         = 1;
      dl_config_pdu->dci_dl_pdu.dci_dl_pdu_rel8.aggregation_level = aggregation;
      DL_req->number_pdu++;

      // Insert PAGING into selected UE list with high priority
      dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].UE_id = -2; // Special UE ID for PAGING
      dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].ue_priority = SCH_DL_PAGING;
      dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].rnti = P_RNTI;
      dlsch_ue_select[CC_id].list[dlsch_ue_select[CC_id].ue_num].nb_rb = 0; // PAGING uses fixed resources
      dlsch_ue_select[CC_id].ue_num++;

      if (dlsch_ue_select[CC_id].ue_num == dlsch_ue_max_num[CC_id]) {
        end_flag[CC_id] = 1;
      }
    }
  }
}

// Insert DLSCH(retransmission) UE into selected UE list
for (CC_id = 0; CC_id < MAX_NUM_CCs; CC_id++) {
  if (mbsfn_flag[CC_id]>0) {
    continue;
  }
